// ============ ADMIN DASHBOARD ============

export function AdminDashboard() {
  const { setActiveTab } = useAppStore();
  const [stats, setStats] = useState({
    total: 0,
    students: 0,
    faculty: 0,
    admins: 0
  });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchStats = async () => {
      try {
        const res = await fetch('/api/users');
        const data = await res.json();
        if (data.success) {
          setStats(data.stats || { total: 0, students: 0, faculty: 0, admins: 0 });
        }
      } catch (error) {
        console.error('Failed to fetch stats:', error);
      } finally {
        setLoading(false);
      }
    };
    fetchStats();
  }, []);

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-xl font-bold">Admin Dashboard</h2>
          <p className="text-sm text-muted-foreground">System overview and management</p>
        </div>
        <div className="text-right">
          <div className="text-3xl font-bold text-red-600">{new Date().getDate()}</div>
          <div className="text-xs text-muted-foreground uppercase">{new Date().toLocaleDateString('en-US', { month: 'short', year: 'numeric' })}</div>
        </div>
      </div>

      <div className="grid grid-cols-2 lg:grid-cols-4 gap-3">
        <Card className="border-0 shadow-md rounded-2xl">
          <CardContent className="p-4 text-center">
            <div className="w-12 h-12 mx-auto mb-2 rounded-xl bg-emerald-100 dark:bg-emerald-900/30 flex items-center justify-center">
              <GraduationCap className="w-6 h-6 text-emerald-600" />
            </div>
            <p className="text-2xl font-bold text-emerald-600">{stats.students}</p>
            <p className="text-xs text-muted-foreground">Total Students</p>
          </CardContent>
        </Card>

        <Card className="border-0 shadow-md rounded-2xl">
          <CardContent className="p-4 text-center">
            <div className="w-12 h-12 mx-auto mb-2 rounded-xl bg-purple-100 dark:bg-purple-900/30 flex items-center justify-center">
              <UserCheck className="w-6 h-6 text-purple-600" />
            </div>
            <p className="text-2xl font-bold text-purple-600">{stats.faculty}</p>
            <p className="text-xs text-muted-foreground">Faculty Members</p>
          </CardContent>
        </Card>

        <Card className="border-0 shadow-md rounded-2xl">
          <CardContent className="p-4 text-center">
            <div className="w-12 h-12 mx-auto mb-2 rounded-xl bg-slate-100 dark:bg-slate-900/30 flex items-center justify-center">
              <Users className="w-6 h-6 text-slate-600" />
            </div>
            <p className="text-2xl font-bold text-slate-600">{stats.total}</p>
            <p className="text-xs text-muted-foreground">Total Users</p>
          </CardContent>
        </Card>

        <Card className="border-0 shadow-md rounded-2xl">
          <CardContent className="p-4 text-center">
            <div className="w-12 h-12 mx-auto mb-2 rounded-xl bg-red-100 dark:bg-red-900/30 flex items-center justify-center">
              <AlertCircle className="w-6 h-6 text-red-600" />
            </div>
            <p className="text-2xl font-bold text-red-600">0</p>
            <p className="text-xs text-muted-foreground">System Alerts</p>
          </CardContent>
        </Card>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <Card className="border-0 shadow-md rounded-2xl cursor-pointer hover:shadow-lg transition-shadow" onClick={() => setActiveTab('import')}>
          <CardContent className="p-6 flex items-center justify-between">
            <div className="flex items-center gap-4">
              <div className="w-12 h-12 rounded-2xl bg-orange-100 dark:bg-orange-900/30 flex items-center justify-center">
                <Upload className="w-6 h-6 text-orange-600" />
              </div>
              <div>
                <h3 className="font-bold">Bulk Import</h3>
                <p className="text-sm text-muted-foreground">Upload users, timetable, marks</p>
              </div>
            </div>
            <ArrowRight className="w-5 h-5 text-muted-foreground" />
          </CardContent>
        </Card>

        <Card className="border-0 shadow-md rounded-2xl cursor-pointer hover:shadow-lg transition-shadow" onClick={() => setActiveTab('users')}>
          <CardContent className="p-6 flex items-center justify-between">
            <div className="flex items-center gap-4">
              <div className="w-12 h-12 rounded-2xl bg-blue-100 dark:bg-blue-900/30 flex items-center justify-center">
                <Users className="w-6 h-6 text-blue-600" />
              </div>
              <div>
                <h3 className="font-bold">User Management</h3>
                <p className="text-sm text-muted-foreground">Manage students and faculty</p>
              </div>
            </div>
            <ArrowRight className="w-5 h-5 text-muted-foreground" />
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

// ============ ADMIN USERS COMPONENT ============

export function AdminUsersPage() {
  const [users, setUsers] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [roleFilter, setRoleFilter] = useState<'all' | 'student' | 'faculty'>('all');
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 20;

  const fetchUsers = async () => {
    setLoading(true);
    try {
      const res = await fetch('/api/users');
      const data = await res.json();
      if (data.success) {
        setUsers(data.users || []);
      }
    } catch (error) {
      console.error('Failed to fetch users:', error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchUsers();
  }, []);

  const filteredUsers = users.filter(user => {
    const matchesSearch = user.name?.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          user.collegeId?.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesRole = roleFilter === 'all' ? true : user.role === roleFilter;
    return matchesSearch && matchesRole;
  });

  const totalPages = Math.ceil(filteredUsers.length / itemsPerPage);
  const paginatedUsers = filteredUsers.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage);

  const handleDeleteUser = async (userId: string) => {
    if (!confirm('Are you sure you want to delete this user? This will remove all their records.')) return;
    try {
      const res = await fetch(`/api/users?id=${userId}`, { method: 'DELETE' });
      const data = await res.json();
      if (data.success) {
        toast.success('User deleted successfully');
        fetchUsers();
      } else {
        toast.error(data.message || 'Failed to delete user');
      }
    } catch {
      toast.error('Failed to delete user');
    }
  };

  return (
    <div className="space-y-4">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-3">
        <div>
          <h2 className="text-xl font-bold">User Management</h2>
          <p className="text-sm text-muted-foreground">Manage system users and their accounts</p>
        </div>
        <Button variant="outline" size="sm" onClick={fetchUsers} disabled={loading} className="rounded-xl h-8">
          <RefreshCw className={`w-3.5 h-3.5 mr-1 ${loading ? 'animate-spin' : ''}`} />
          Refresh
        </Button>
      </div>

      <div className="flex flex-col sm:flex-row gap-3">
        <div className="relative flex-1">
          <Search className="w-4 h-4 absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" />
          <Input 
            placeholder="Search by name or ID..." 
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="pl-9 rounded-xl h-10"
          />
        </div>
        <div className="flex gap-2">
          {['all', 'student', 'faculty'].map((role) => (
            <Button
              key={role}
              variant={roleFilter === role ? 'default' : 'outline'}
              size="sm"
              onClick={() => setRoleFilter(role as any)}
              className="rounded-xl h-10 px-4 capitalize"
            >
              {role}s
            </Button>
          ))}
        </div>
      </div>

      <Card className="border-0 shadow-md rounded-2xl overflow-hidden">
        <div className="overflow-x-auto">
          {loading ? (
            <div className="flex items-center justify-center py-12">
              <div className="w-8 h-8 border-2 border-slate-500 border-t-transparent rounded-full animate-spin" />
            </div>
          ) : (
            <table className="w-full">
              <thead>
                <tr className="bg-gray-50 dark:bg-gray-800 border-b">
                  <th className="text-left py-3 px-4 text-xs font-medium text-muted-foreground">User</th>
                  <th className="text-left py-3 px-4 text-xs font-medium text-muted-foreground">ID / Reg No</th>
                  <th className="text-left py-3 px-4 text-xs font-medium text-muted-foreground">Role</th>
                  <th className="text-left py-3 px-4 text-xs font-medium text-muted-foreground">Email</th>
                  <th className="text-right py-3 px-4 text-xs font-medium text-muted-foreground">Actions</th>
                </tr>
              </thead>
              <tbody>
                {paginatedUsers.length === 0 ? (
                  <tr>
                    <td colSpan={5} className="py-8 text-center text-muted-foreground">No users found</td>
                  </tr>
                ) : (
                  paginatedUsers.map((user) => (
                    <tr key={user.id} className="border-b last:border-0 hover:bg-slate-50 dark:hover:bg-slate-900/10 transition-colors">
                      <td className="py-3 px-4">
                        <div className="flex items-center gap-3">
                          <div className="w-8 h-8 rounded-full bg-slate-200 dark:bg-slate-800 flex items-center justify-center text-xs font-bold">
                            {user.name?.[0]?.toUpperCase()}
                          </div>
                          <span className="text-sm font-medium">{user.name}</span>
                        </div>
                      </td>
                      <td className="py-3 px-4 font-mono text-sm">{user.collegeId}</td>
                      <td className="py-3 px-4">
                        <Badge variant="outline" className={`text-[10px] rounded-lg capitalize ${
                          user.role === 'admin' ? 'bg-red-50 text-red-700' :
                          user.role === 'faculty' ? 'bg-purple-50 text-purple-700' : 'bg-blue-50 text-blue-700'
                        }`}>
                          {user.role}
                        </Badge>
                      </td>
                      <td className="py-3 px-4 text-sm text-muted-foreground">{user.email || '-'}</td>
                      <td className="py-3 px-4 text-right">
                        <Button 
                          variant="ghost" 
                          size="icon" 
                          onClick={() => handleDeleteUser(user.id)}
                          disabled={user.role === 'admin'}
                          className="h-8 w-8 text-red-500 hover:text-red-700 hover:bg-red-50"
                        >
                          <Trash2 className="w-4 h-4" />
                        </Button>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          )}
        </div>
      </Card>

      {totalPages > 1 && (
        <div className="flex items-center justify-center gap-2 mt-4">
          <Button
            variant="outline"
            size="sm"
            onClick={() => setCurrentPage(p => Math.max(1, p - 1))}
            disabled={currentPage === 1}
            className="rounded-xl"
          >
            <ChevronLeft className="w-4 h-4" />
          </Button>
          <span className="text-sm">Page {currentPage} of {totalPages}</span>
          <Button
            variant="outline"
            size="sm"
            onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))}
            disabled={currentPage === totalPages}
            className="rounded-xl"
          >
            <ChevronRight className="w-4 h-4" />
          </Button>
        </div>
      )}
    </div>
  );
}

// ============ ADMIN IMPORT COMPONENT ============

export function AdminImportPage() {
  const { user, triggerDataUpdate } = useAppStore();
  const [importing, setImporting] = useState(false);
  const [importResult, setImportResult] = useState<any>(null);
  const [showResultDialog, setShowResultDialog] = useState(false);
  const [showDeleteDialog, setShowDeleteDialog] = useState<'students' | 'faculty' | 'all' | null>(null);
  const [deleting, setDeleting] = useState(false);
  const [importMode, setImportMode] = useState<'append' | 'replace'>('append');
  
  const [stats, setStats] = useState({ total: 0, students: 0, faculty: 0 });
  const [timetableSummaries, setTimetableSummaries] = useState<{ section: string; count: number }[]>([]);

  const [resetPassword, setResetPassword] = useState('');
  const [resetRole, setResetRole] = useState<'students' | 'faculty' | 'all'>('students');
  const [showResetDialog, setShowResetDialog] = useState(false);
  const [resetting, setResetting] = useState(false);
  const [initializingAcademic, setInitializingAcademic] = useState(false);

  const studentCsvRef = useRef<HTMLInputElement>(null);
  const facultyCsvRef = useRef<HTMLInputElement>(null);
  const cgpaCsvRef = useRef<HTMLInputElement>(null);
  const attendanceCsvRef = useRef<HTMLInputElement>(null);
  const timetableRef = useRef<HTMLInputElement>(null);

  const fetchData = async () => {
    try {
      const uRes = await fetch('/api/users');
      const uData = await uRes.json();
      if (uData.success) {
        setStats({ total: uData.stats.total, students: uData.stats.students, faculty: uData.stats.faculty });
      }

      const tRes = await fetch('/api/timetable');
      const tData = await tRes.json();
      if (tData.success) {
        setTimetableSummaries(tData.summaries || []);
      }
    } catch (e) {
      console.error(e);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const handleCsvImport = async (role: 'student' | 'faculty') => {
    const fileInput = role === 'student' ? studentCsvRef.current : facultyCsvRef.current;
    if (!fileInput?.files?.[0]) return;

    setImporting(true);
    const formData = new FormData();
    formData.append('file', fileInput.files[0]);
    formData.append('role', role);
    formData.append('mode', importMode);

    try {
      const res = await fetch('/api/import-users', { method: 'POST', body: formData });
      const result = await res.json();
      setImportResult(result);
      setShowResultDialog(true);
      if (result.success > 0) {
        fetchData();
        triggerDataUpdate();
      }
    } catch (error) {
      toast.error('Failed to import users');
    } finally {
      setImporting(false);
      fileInput.value = '';
    }
  };

  const handleCgpaImport = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files?.[0]) return;
    setImporting(true);
    const formData = new FormData();
    formData.append('file', e.target.files[0]);
    formData.append('mode', importMode);

    try {
      const res = await fetch('/api/import-academic', { method: 'POST', body: formData });
      const result = await res.json();
      setImportResult(result);
      setShowResultDialog(true);
      if (result.success > 0) triggerDataUpdate();
    } catch (error) { toast.error('Failed to import academic data'); }
    finally { setImporting(false); e.target.value = ''; }
  };

  const handleAttendanceImport = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files?.[0]) return;
    setImporting(true);
    const formData = new FormData();
    formData.append('file', e.target.files[0]);
    formData.append('mode', importMode);

    try {
      const res = await fetch('/api/import-attendance', { method: 'POST', body: formData });
      const result = await res.json();
      setImportResult(result);
      setShowResultDialog(true);
      if (result.success > 0) triggerDataUpdate();
    } catch (error) { toast.error('Failed to import attendance'); }
    finally { setImporting(false); e.target.value = ''; }
  };

  const handleTimetableImport = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files?.[0]) return;
    setImporting(true);
    const formData = new FormData();
    formData.append('file', e.target.files[0]);

    try {
      const res = await fetch('/api/timetable-import', { method: 'POST', body: formData });
      const result = await res.json();
      if (result.success) {
        toast.success(`Timetable imported: ${result.count} entries across ${result.sections.join(', ')}`);
        fetchData();
        triggerDataUpdate();
      } else {
        toast.error(result.message || 'Failed to import timetable');
      }
    } catch (error) { toast.error('Failed to import timetable'); }
    finally { setImporting(false); e.target.value = ''; }
  };

  const handleInitializeAcademic = async () => {
    setInitializingAcademic(true);
    try {
      const res = await fetch('/api/initialize-academic', { method: 'POST' });
      const result = await res.json();
      if (result.success) {
        toast.success(result.message);
        triggerDataUpdate();
      } else { toast.error(result.message); }
    } catch { toast.error('Failed to initialize'); }
    finally { setInitializingAcademic(false); }
  };

  const handleDeleteAll = async (type: 'students' | 'faculty' | 'all') => {
    setDeleting(true);
    try {
      const res = await fetch(`/api/users-cleanup?type=${type}`, { method: 'DELETE' });
      const data = await res.json();
      if (data.success) {
        toast.success(`Deleted ${data.count} records`);
        setShowDeleteDialog(null);
        fetchData();
        triggerDataUpdate();
      } else { toast.error(data.message); }
    } catch { toast.error('Failed to delete records'); }
    finally { setDeleting(false); }
  };

  const handleResetPasswords = async () => {
    setResetting(true);
    try {
      const res = await fetch('/api/reset-passwords', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ role: resetRole, newPassword: resetPassword }),
      });
      const data = await res.json();
      if (data.success) {
        toast.success(`Reset passwords for ${data.count} users`);
        setShowResetDialog(false);
        setResetPassword('');
      } else { toast.error(data.message); }
    } catch { toast.error('Reset failed'); }
    finally { setResetting(false); }
  };

  const downloadTemplate = (type: string) => {
    let content = '';
    let filename = '';
    if (type === 'student') {
       content = 'collegeId,name,email,password,phone,branch,section,year,semester,parentEmail,parentPhone\nREG001,John Doe,john@example.com,password123,9876543210,CSE,A,4,7,parent@example.com,9876543211';
       filename = 'students_template.csv';
    } else if (type === 'faculty') {
       content = 'collegeId,name,password,email,phone,department\nFAC001,Dr. Smith,pass123,smith@univ.edu,9876543210,CSE';
       filename = 'faculty_template.csv';
    } else if (type === 'attendance') {
       content = 'collegeId,date,subject,status,topicCovered\nREG001,2024-03-25,CSE-401,present,React Components';
       filename = 'attendance_template.csv';
    } else if (type === 'academic') {
       content = 'collegeId,Subject Code,Grade,Subject Name,Credit,Sem\nREG001,CSE-101,A,Data Structures,4,1';
       filename = 'academic_template.csv';
    }
    
    if (content) {
      const blob = new Blob([content], { type: 'text/csv' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a'); a.href = url; a.download = filename; a.click();
      URL.revokeObjectURL(url);
    }
  };

  return (
    <div className="space-y-4">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-3">
        <div>
          <h2 className="text-xl font-bold">Import Center</h2>
          <p className="text-sm text-muted-foreground">Bulk upload system data</p>
        </div>
        <div className="flex items-center gap-2 p-1 bg-gray-100 dark:bg-gray-800 rounded-xl">
           <Button size="sm" variant={importMode === 'append' ? 'default' : 'ghost'} onClick={() => setImportMode('append')} className="rounded-lg h-8 text-xs">Append</Button>
           <Button size="sm" variant={importMode === 'replace' ? 'default' : 'ghost'} onClick={() => setImportMode('replace')} className="rounded-lg h-8 text-xs">Replace</Button>
        </div>
      </div>

      <Tabs defaultValue="students" className="w-full">
        <TabsList className="grid grid-cols-5 w-full rounded-xl">
          <TabsTrigger value="students" className="rounded-lg text-xs">Students</TabsTrigger>
          <TabsTrigger value="academic" className="rounded-lg text-xs">Marks</TabsTrigger>
          <TabsTrigger value="attendance" className="rounded-lg text-xs">Attendance</TabsTrigger>
          <TabsTrigger value="faculty" className="rounded-lg text-xs">Faculty</TabsTrigger>
          <TabsTrigger value="timetable" className="rounded-lg text-xs">Timetable</TabsTrigger>
        </TabsList>

        <TabsContent value="students" className="mt-4 space-y-4">
          <Card className="border-0 shadow-md rounded-2xl">
            <CardHeader className="pb-2">
              <CardTitle className="text-sm font-semibold flex items-center gap-2"><GraduationCap className="w-4 h-4 text-emerald-600" />Import Students</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
               <div className="flex gap-2">
                  <Button variant="outline" size="sm" onClick={() => downloadTemplate('student')} className="rounded-xl flex-1"><Download className="w-4 h-4 mr-1" /> Template</Button>
                  <input ref={studentCsvRef} type="file" accept=".csv" className="hidden" onChange={() => handleCsvImport('student')} />
                  <Button size="sm" onClick={() => studentCsvRef.current?.click()} disabled={importing} className="rounded-xl flex-1 bg-emerald-600 hover:bg-emerald-700 text-white">
                    {importing ? <RefreshCw className="w-4 h-4 mr-1 animate-spin" /> : <Upload className="w-4 h-4 mr-1" />} Import CSV
                  </Button>
               </div>
            </CardContent>
          </Card>
          
          <Card className="border-0 shadow-md rounded-2xl border-emerald-100">
            <CardHeader className="pb-2">
              <CardTitle className="text-sm font-semibold flex items-center gap-2"><RefreshCw className="w-4 h-4 text-emerald-600" />Risk Initialization</CardTitle>
            </CardHeader>
            <CardContent className="space-y-2">
              <p className="text-xs text-muted-foreground">Recalculate risk assessments and Activity Points for all students.</p>
              <Button onClick={handleInitializeAcademic} disabled={initializingAcademic} className="w-full rounded-xl bg-emerald-600 hover:bg-emerald-700">
                {initializingAcademic ? <RefreshCw className="w-4 h-4 mr-1 animate-spin" /> : <RefreshCw className="w-4 h-4 mr-1" />} Initialize Records
              </Button>
            </CardContent>
          </Card>
        </TabsContent>

        <TabsContent value="academic" className="mt-4">
          <Card className="border-0 shadow-md rounded-2xl">
            <CardHeader><CardTitle className="text-sm font-semibold flex items-center gap-2"><ArrowRight className="w-4 h-4 text-orange-600" />Import Subject Marks</CardTitle></CardHeader>
            <CardContent className="space-y-4">
               <div className="flex gap-2">
                  <Button variant="outline" size="sm" onClick={() => downloadTemplate('academic')} className="rounded-xl flex-1"><Download className="w-4 h-4 mr-1" /> Template</Button>
                  <input ref={cgpaCsvRef} type="file" accept=".csv" className="hidden" onChange={handleCgpaImport} />
                  <Button size="sm" onClick={() => cgpaCsvRef.current?.click()} className="rounded-xl flex-1 bg-orange-600 hover:bg-orange-700 text-white"><Upload className="w-4 h-4 mr-1" /> Import CSV</Button>
               </div>
            </CardContent>
          </Card>
        </TabsContent>

        <TabsContent value="attendance" className="mt-4">
          <Card className="border-0 shadow-md rounded-2xl">
            <CardHeader><CardTitle className="text-sm font-semibold flex items-center gap-2"><CheckCircle2 className="w-4 h-4 text-blue-600" />Import Daily logs</CardTitle></CardHeader>
            <CardContent className="space-y-4">
               <div className="flex gap-2">
                  <Button variant="outline" size="sm" onClick={() => downloadTemplate('attendance')} className="rounded-xl flex-1"><Download className="w-4 h-4 mr-1" /> Template</Button>
                  <input ref={attendanceCsvRef} type="file" accept=".csv" className="hidden" onChange={handleAttendanceImport} />
                  <Button size="sm" onClick={() => attendanceCsvRef.current?.click()} className="rounded-xl flex-1 bg-blue-600 hover:bg-blue-700 text-white"><Upload className="w-4 h-4 mr-1" /> Import CSV</Button>
               </div>
            </CardContent>
          </Card>
        </TabsContent>

        <TabsContent value="faculty" className="mt-4">
           <Card className="border-0 shadow-md rounded-2xl">
             <CardHeader><CardTitle className="text-sm font-semibold flex items-center gap-2"><UserCheck className="w-4 h-4 text-purple-600" />Import Faculty</CardTitle></CardHeader>
             <CardContent className="space-y-4">
                <div className="flex gap-2">
                   <Button variant="outline" size="sm" onClick={() => downloadTemplate('faculty')} className="rounded-xl flex-1"><Download className="w-4 h-4 mr-1" /> Template</Button>
                   <input ref={facultyCsvRef} type="file" accept=".csv" className="hidden" onChange={() => handleCsvImport('faculty')} />
                   <Button size="sm" onClick={() => facultyCsvRef.current?.click()} className="rounded-xl flex-1 bg-purple-600 hover:bg-purple-700 text-white"><Upload className="w-4 h-4 mr-1" /> Import CSV</Button>
                </div>
             </CardContent>
           </Card>
        </TabsContent>

        <TabsContent value="timetable" className="mt-4 space-y-4">
           <Card className="border-0 shadow-md rounded-2xl">
             <CardHeader><CardTitle className="text-sm font-semibold">Upload Timetable Excel</CardTitle></CardHeader>
             <CardContent className="space-y-4">
                <input ref={timetableRef} type="file" accept=".xlsx,.xls" className="hidden" onChange={handleTimetableImport} />
                <Button size="sm" onClick={() => timetableRef.current?.click()} className="w-full rounded-xl bg-indigo-600 hover:bg-indigo-700 text-white"><Upload className="w-4 h-4 mr-2" /> Select Excel File</Button>
             </CardContent>
           </Card>
           
           <div className="space-y-2">
              <h3 className="text-xs font-bold uppercase text-muted-foreground px-1">Active Sections</h3>
              <div className="grid grid-cols-2 sm:grid-cols-3 gap-2">
                 {timetableSummaries.map(s => (
                   <div key={s.section} className="p-2 rounded-xl bg-secondary/50 border flex items-center justify-between text-xs">
                      <span className="font-bold">Sec {s.section}</span>
                      <div className="w-1.5 h-1.5 rounded-full bg-green-500" />
                   </div>
                 ))}
              </div>
           </div>
        </TabsContent>
      </Tabs>

      {/* Advanced Tools */}
      <Card className="border-0 shadow-md rounded-2xl border-red-100 overflow-hidden">
        <CardHeader className="bg-red-50/50 dark:bg-red-950/20 pb-3"><CardTitle className="text-sm font-bold text-red-600">Danger Zone</CardTitle></CardHeader>
        <CardContent className="p-4 space-y-4">
           <div className="flex gap-2">
              <Button variant="outline" size="sm" className="flex-1 rounded-xl" onClick={() => setShowDeleteDialog('students')}>Delete Students</Button>
              <Button variant="outline" size="sm" className="flex-1 rounded-xl" onClick={() => setShowDeleteDialog('faculty')}>Delete Faculty</Button>
           </div>
           
           <Separator />
           
           <div className="space-y-2">
              <Label className="text-xs">Bulk Password Reset ({resetRole})</Label>
              <div className="flex gap-2">
                 <Input value={resetPassword} onChange={e=>setResetPassword(e.target.value)} placeholder="New password" size={1} className="h-9 rounded-xl flex-1 text-xs" />
                 <Button size="sm" onClick={() => setShowResetDialog(true)} disabled={!resetPassword || resetPassword.length < 6} className="rounded-xl h-9">Reset</Button>
              </div>
           </div>
        </CardContent>
      </Card>

      {/* Dialogs */}
      <Dialog open={showResultDialog} onOpenChange={setShowResultDialog}>
         <DialogContent className="rounded-2xl">
            <DialogHeader><DialogTitle>Import Results</DialogTitle></DialogHeader>
            {importResult && (
               <div className="space-y-4 text-sm">
                  <div className="grid grid-cols-2 gap-4 text-center">
                     <div className="p-4 rounded-2xl bg-green-50 text-green-700"><p className="text-2xl font-bold">{importResult.success}</p><p>Success</p></div>
                     <div className="p-4 rounded-2xl bg-red-50 text-red-700"><p className="text-2xl font-bold">{importResult.failed}</p><p>Failed</p></div>
                  </div>
                  {importResult.errors.length > 0 && (
                     <div className="max-h-40 overflow-y-auto p-2 bg-muted rounded-xl text-xs space-y-1">
                        {importResult.errors.slice(0, 10).map((err: string, i: number) => <p key={i} className="text-red-600">{err}</p>)}
                     </div>
                  )}
               </div>
            )}
            <DialogFooter><Button onClick={() => setShowResultDialog(false)} className="rounded-xl">Close</Button></DialogFooter>
         </DialogContent>
      </Dialog>
      
      <Dialog open={!!showDeleteDialog} onOpenChange={() => setShowDeleteDialog(null)}>
         <DialogContent className="rounded-2xl">
            <DialogHeader><DialogTitle className="text-red-600">Permanent Deletion</DialogTitle><DialogDescription>Are you absolutely sure? This cannot be undone.</DialogDescription></DialogHeader>
            <DialogFooter className="gap-2">
               <Button variant="outline" onClick={() => setShowDeleteDialog(null)} className="flex-1 rounded-xl">Cancel</Button>
               <Button variant="destructive" onClick={() => handleDeleteAll(showDeleteDialog!)} className="flex-1 rounded-xl">Confirm Delete</Button>
            </DialogFooter>
         </DialogContent>
      </Dialog>

      <Dialog open={showResetDialog} onOpenChange={setShowResetDialog}>
         <DialogContent className="rounded-2xl">
            <DialogHeader><DialogTitle>Bulk Password Reset</DialogTitle><DialogDescription>Reset passwords for {resetRole} to "{resetPassword}"?</DialogDescription></DialogHeader>
            <DialogFooter className="gap-2">
               <Button variant="outline" onClick={() => setShowResetDialog(false)} className="flex-1 rounded-xl">Cancel</Button>
               <Button onClick={handleResetPasswords} className="flex-1 rounded-xl">Continue</Button>
            </DialogFooter>
         </DialogContent>
      </Dialog>
    </div>
  );
}
